function escapeHtml(str) {
  return str.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
}

function generatePage(page) {
  let html = template;

  // Replace title
  html = html.replace(
    /<title>[^<]*<\/title>/,
    `<title>${escapeHtml(page.title)}</title>`
  );

  // Replace meta description
  html = html.replace(
    /<meta name="description" content="[^"]*"/,
    `<meta name="description" content="${escapeHtml(page.description)}"`
  );

  // Replace canonical URL
  html = html.replace(
    /<link rel="canonical" href="[^"]*"/,
    `<link rel="canonical" href="${DOMAIN}${page.path}"`
  );

  // Replace OG tags
  html = html.replace(
    /<meta property="og:title" content="[^"]*"/,
    `<meta property="og:title" content="${escapeHtml(page.title)}"`
  );
  html = html.replace(
    /<meta property="og:description" content="[^"]*"/,
    `<meta property="og:description" content="${escapeHtml(page.description)}"`
  );
  html = html.replace(
    /<meta property="og:url" content="[^"]*"/,
    `<meta property="og:url" content="${DOMAIN}${page.path}"`
  );

  // Replace Twitter tags
  html = html.replace(
    /<meta name="twitter:title" content="[^"]*"/,
    `<meta name="twitter:title" content="${escapeHtml(page.title)}"`
  );
  html = html.replace(
    /<meta name="twitter:description" content="[^"]*"/,
    `<meta name="twitter:description" content="${escapeHtml(page.description)}"`
  );

  // Build structured data for this page
  let schemaScripts = '';
  
  // Add Article schema for blog posts
  if (page.path.startsWith('/blog/') && page.path !== '/blog') {
    const slug = page.path.replace('/blog/', '');
    const articleSchema = {
      "@context": "https://schema.org",
      "@type": "BlogPosting",
      "headline": page.title.replace(/ \| Alhamd Academy.*$/, ''),
      "description": page.description,
      "url": `${DOMAIN}${page.path}`,
      "datePublished": "2025-01-15",
      "dateModified": "2026-03-24",
      "author": { "@type": "Organization", "name": "Alhamd Academy", "url": DOMAIN },
      "publisher": {
        "@type": "Organization",
        "name": "Alhamd Academy",
        "logo": { "@type": "ImageObject", "url": `${DOMAIN}/favicon-512.png`, "width": 512, "height": 512 }
      },
      "mainEntityOfPage": { "@type": "WebPage", "@id": `${DOMAIN}${page.path}` },
      "inLanguage": "en"
    };
    const breadcrumb = {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      "itemListElement": [
        { "@type": "ListItem", "position": 1, "name": "Home", "item": `${DOMAIN}/` },
        { "@type": "ListItem", "position": 2, "name": "Blog", "item": `${DOMAIN}/blog` },
        { "@type": "ListItem", "position": 3, "name": page.title.replace(/ \| Alhamd Academy.*$/, ''), "item": `${DOMAIN}${page.path}` }
      ]
    };
    schemaScripts = `<script type="application/ld+json">${JSON.stringify(articleSchema)}</script><script type="application/ld+json">${JSON.stringify(breadcrumb)}</script>`;
  }
  // Add breadcrumb schema for service pages
  else if (page.path !== '/' && !page.path.startsWith('/blog') && !page.path.startsWith('/learn-quran')) {
    const pageName = page.title.replace(/ \| Alhamd Academy.*$/, '').replace(/ - Alhamd Academy.*$/, '');
    const breadcrumb = {
      "@context": "https://schema.org",
      "@type": "BreadcrumbList",
      "itemListElement": [
        { "@type": "ListItem", "position": 1, "name": "Home", "item": `${DOMAIN}/` },
        { "@type": "ListItem", "position": 2, "name": pageName, "item": `${DOMAIN}${page.path}` }
      ]
    };
    schemaScripts = `<script type="application/ld+json">${JSON.stringify(breadcrumb)}</script>`;
  }

  // Inject content into the root div (React will replace it on hydration)
  // Handle both empty root and homepage with existing seo-content
  const contentHtml = `<div id="root"><div id="seo-content" style="font-family:system-ui,sans-serif;max-width:800px;margin:0 auto;padding:2rem;">${page.content}<footer><nav><p><strong>Alhamd Academy – Online Quran, Arabic & Islamic Studies</strong></p><ul><li><a href="${DOMAIN}/">Home</a></li><li><a href="${DOMAIN}/online-quran-classes">Online Quran Classes</a></li><li><a href="${DOMAIN}/tajweed-course-online">Tajweed Course</a></li><li><a href="${DOMAIN}/quran-memorization-hifz">Quran Memorization</a></li><li><a href="${DOMAIN}/arabic-for-kids">Arabic for Kids</a></li><li><a href="${DOMAIN}/arabic-for-adults">Arabic for Adults</a></li><li><a href="${DOMAIN}/islamic-studies-online">Islamic Studies</a></li><li><a href="${DOMAIN}/ijazah-program">Ijazah Program</a></li><li><a href="${DOMAIN}/female-quran-teacher">Female Quran Teacher</a></li><li><a href="${DOMAIN}/free-trial">Free Trial</a></li><li><a href="${DOMAIN}/blog">Blog</a></li><li><a href="${DOMAIN}/videos">Videos</a></li></ul><p>Contact: <a href="https://wa.me/201271134828">WhatsApp +201271134828</a> | <!--email_off-->info@alhamdacademy.net<!--/email_off--></p></nav></footer></div></div>`;


  // Replace entire root div content — use a robust approach that handles
  // the complex hero skeleton markup in the homepage template
  const rootOpenTag = '<div id="root">';
  const rootIdx = html.indexOf(rootOpenTag);
  if (rootIdx !== -1) {
    // Find the matching closing </div> for #root by counting nesting
    let depth = 0;
    let searchStart = rootIdx + rootOpenTag.length;
    let closingIdx = -1;
    while (searchStart < html.length) {
      const nextOpen = html.indexOf('<div', searchStart);
      const nextClose = html.indexOf('</div>', searchStart);
      if (nextClose === -1) break;
      if (nextOpen !== -1 && nextOpen < nextClose) {
        depth++;
        searchStart = nextOpen + 4;
      } else {
        if (depth === 0) {
          closingIdx = nextClose + '</div>'.length;
          break;
        }
        depth--;
        searchStart = nextClose + '</div>'.length;
      }
    }
    if (closingIdx !== -1) {
      html = html.substring(0, rootIdx) + contentHtml + html.substring(closingIdx);
    }
  }

  // Inject schema scripts into head
  if (schemaScripts) {
    html = html.replace('</head>', `${schemaScripts}\n</head>`);
  }

  // Honor per-page noindex flag
  if (page.noindex) {
    // Remove any existing robots meta then inject noindex
    html = html.replace(/<meta\s+name="robots"[^>]*>/gi, '');
    html = html.replace('</head>', `<meta name="robots" content="noindex,nofollow" />\n</head>`);
  }

  return html;
}

// Generate all pages
let count = 0;
for (const page of pages) {
  const html = generatePage(page);
  const dirPath = join(DIST, page.path);

  if (!existsSync(dirPath)) {
    mkdirSync(dirPath, { recursive: true });
  }

  writeFileSync(join(dirPath, 'index.html'), html, 'utf-8');
  count++;
}

console.log(`✅ Generated ${count} static HTML pages for SEO crawlers.`);
